body:
I've had a very difficult time finding information on this specific subject, so I'm not sure if it is a bug or unsupported. I have a small piece of verilog code:
```verilog
module Pin(
       input wire        direction,
       input wire [7:0]  data_write,
       output wire [7:0] data_read,
       inout wire [7:0]  io_port,
       input  clk
       );

   reg [7:0] data_out;
   reg [7:0] data_in;

   assign io_port = direction ? data_out : 8'hzz;
   assign data_read = data_in;

   always @ (posedge clk)
     begin
     data_in  <= io_port;
     data_out <= data_write;
   end

endmodule
```
The test I want to do is to check inout port functionality by repeatedly doing four operations:
1. Set `direction` to 1 and write to `data_write` 
2. Read that data back from `io_port`
3. Set `direction` to 0 and write to `io_port`
4. Read that data back from `data_read`

This is the simple testbench I wrote to perform these operations:
```c++
#include "VTop.h"
#include "verilated.h"
#include "verilated_vpi.h"
#include <iostream>
#include <string>

int main( int argc, char* argv[] ) {
  auto ContextP = new VerilatedContext();
  ContextP->threads(1);
  ContextP->randReset(2);
  ContextP->traceEverOn(true);
  const char *empty{};
  ContextP->commandArgs(0, &empty);
  auto Top = new VTop(ContextP, "");

  char directionName[] = "direction";
  char data_writeName[] = "data_write";
  char data_readName[] = "data_read";
  char io_portName[] = "io_port";
  char clkName[] = "clk";
  vpiHandle directionHandle = vpi_handle_by_name((char *)directionName, NULL);
  vpiHandle data_writeHandle = vpi_handle_by_name((char *)data_writeName, NULL);
  vpiHandle data_readHandle = vpi_handle_by_name((char *)data_readName, NULL);
  vpiHandle io_portHandle = vpi_handle_by_name((char *)io_portName, NULL);
  vpiHandle clkHandle = vpi_handle_by_name((char *)clkName, NULL);

  t_vpi_value oneVal;
  oneVal.format = vpiVectorVal;
  oneVal.value.vector = new s_vpi_vecval[1];
  oneVal.value.vector->aval = 1;
  oneVal.value.vector->bval = 0;
  t_vpi_value zeroVal;
  zeroVal.format = vpiVectorVal;
  zeroVal.value.vector = new s_vpi_vecval[1];
  zeroVal.value.vector->aval = 0;
  zeroVal.value.vector->bval = 0;
  t_vpi_value aaVal;
  aaVal.format = vpiVectorVal;
  aaVal.value.vector = new s_vpi_vecval[1];
  aaVal.value.vector->aval = 0xAA;
  aaVal.value.vector->bval = 0;
  t_vpi_value bbVal;
  bbVal.format = vpiVectorVal;
  bbVal.value.vector = new s_vpi_vecval[1];
  bbVal.value.vector->aval = 0xBB;
  bbVal.value.vector->bval = 0;


  for (size_t i=0; i<5; i++) {
    // set direction to 1 (inout will be readable), write 0xAA to data_write
    vpi_put_value(directionHandle, &oneVal, NULL, vpiNoDelay);
    Top->eval();
    vpi_put_value(data_writeHandle, &aaVal, NULL, vpiNoDelay);
    Top->eval();
    //cycle clock
    vpi_put_value(clkHandle, &zeroVal, NULL, vpiNoDelay);
    Top->eval();
    vpi_put_value(clkHandle, &oneVal, NULL, vpiNoDelay);
    Top->eval();

    // read inout port
    s_vpi_value inout_val;
    inout_val.format = vpiVectorVal;
    inout_val.value.vector = new s_vpi_vecval[1];
    vpi_get_value(io_portHandle, &inout_val);
    std::cout << "io_port has value " << std::hex << inout_val.value.vector->aval << "; should be 0xaa" << std::endl;

    // set direction to 0 (inout will be writeable), write 0xBB to io_port
    vpi_put_value(directionHandle, &zeroVal, NULL, vpiNoDelay);
    Top->eval();
    vpi_put_value(io_portHandle, &bbVal, NULL, vpiNoDelay);
    Top->eval();
    vpi_put_value(clkHandle, &zeroVal, NULL, vpiNoDelay);
    Top->eval();
    vpi_put_value(clkHandle, &oneVal, NULL, vpiNoDelay);
    Top->eval();

    // read data_read port
    s_vpi_value read_val;
    read_val.format = vpiVectorVal;
    read_val.value.vector = new s_vpi_vecval[1];
    vpi_get_value(io_portHandle, &read_val);
    std::cout << "data_read has value " << std::hex << read_val.value.vector->aval << "; should be 0xbb" << std::endl;
  }
}
```
This program mimics testing I've been doing with this verilated model elsewhere and this is as simple as I could get the example.  As such, I'm verilating and compiling the code as similar to the external testing as I can. Verilation command:
`verilator --build --cc --vpi --public-flat-rw -CFLAGS "-DVL_NO_LEGACY -fPIC -std=c++17" --Mdir ./ -y ./ --prefix VTop --top-module Pin ./Pin.sv`
Simulation output:
```
io_port has value aa; should be 0xaa
data_read has value 0; should be 0xbb
io_port has value aa; should be 0xaa
data_read has value 0; should be 0xbb
io_port has value aa; should be 0xaa
data_read has value 0; should be 0xbb
io_port has value aa; should be 0xaa
data_read has value 0; should be 0xbb
io_port has value aa; should be 0xaa
data_read has value 0; should be 0xbb
```
I was surprised to get this output, since it is incorrect but in the opposite way as I had seen in my testing elsewhere. The `inout` port seems to only be functioning correctly as an `output` port. So, when I matched the verilator command to the other testing I was doing by adding the flag for inout pins like this:
`verilator --build --cc --vpi --pins-inout-enables --public-flat-rw -CFLAGS "-DVL_NO_LEGACY -fPIC -std=c++17" --Mdir ./ -y ./ --prefix VTop --top-module Pin ./Pin.sv`
Now, the output is incorrect as I was seeing elsewhere:
```io_port has value 13; should be 0xaa
data_read has value bb; should be 0xbb
io_port has value bb; should be 0xaa
data_read has value bb; should be 0xbb
io_port has value bb; should be 0xaa
data_read has value bb; should be 0xbb
io_port has value bb; should be 0xaa
data_read has value bb; should be 0xbb
io_port has value bb; should be 0xaa
data_read has value bb; should be 0xbb
```
The `inout` port now seems to only function as an `input` port (i.e., the value being read back from it is simply the last one assigned to it externally, instead of being driven by the model). Unfortunately, neither of these outputs show the behavior I would expect. I am also unsure why the `--pins-inout-enables` flag changes the behavior since the testbench code doesn't change at all and VPI does not even seem to be aware of the extra `__en` and `__out` ports, which the flag creates for use when directly accessing the verilated model's ports. Is this a limitation of verilator or VPI? Am I missing something to get this example working properly?
